content => {
  // ============================================================
  // Izumi 分层持久化缓存 (方案 C + 分层)
  // 版本: v4
  // ============================================================
  const TEMP = window.SPresetTempData || {};
  const STORAGE_KEY = 'IzumiCache_V4';

  // --- 简易 hash 工具 ---
  const hashStr = (s) => {
    let h = 0;
    for (let i = 0; i < s.length; i++) {
      h = ((h << 5) - h) + s.charCodeAt(i);
      h |= 0;
    }
    return 'z' + (h >>> 0).toString(36);
  };

  const now = () => Date.now();

  // --- 从 sessionStorage 加载持久化缓存 ---
  const loadPersistent = () => {
    try {
      const raw = sessionStorage.getItem(STORAGE_KEY);
      return raw ? JSON.parse(raw) : {};
    } catch (e) {
      return {};
    }
  };

  // --- 保存持久化缓存 ---
  const savePersistent = (obj) => {
    try {
      sessionStorage.setItem(STORAGE_KEY, JSON.stringify(obj));
    } catch (e) {
      // 存储满时降级为内存
    }
  };

  // --- 初始化 ---
  const chatId = window.SillyTavern.getContext().chatId;
  // 内存级（会话级）
  if (!TEMP.IzumiCache) TEMP.IzumiCache = {};
  if (!TEMP.IzumiCache[chatId]) {
    TEMP.IzumiCache[chatId] = { vars: {}, cachedHashes: new Set(), born: now() };
  }
  const mem = TEMP.IzumiCache[chatId];

  // 持久化级（画像级）
  const persistent = loadPersistent();
  if (!persistent[chatId]) {
    persistent[chatId] = { vars: {}, hashes: {}, born: now() };
  }
  const pst = persistent[chatId];

  // --- TTL 清理（30 分钟） ---
  const TTL = 30 * 60 * 1000;
  for (const cid of Object.keys(persistent)) {
    if (now() - persistent[cid].born > TTL) {
      delete persistent[cid];
    }
  }
  savePersistent(persistent);

  // --- 检测是否开启缓存 ---
  const ENABLE_ID = 'cache-enable-003';
  const cacheEnabled = (() => {
    const po = window.SillyTavern.getContext().preset?.prompt_order?.[0]?.order;
    if (!po) return true;
