  // ==========================================================
  content = content.replace(
    /\{\{setvar::(?:profile::)?([^:}]+)::([\s\S]*?)\}\}/g,
    (match, key, rawValue, offset, src) => {
      const isProfile = /\{\{setvar::profile::/.test(src.slice(Math.max(0, offset - 20), offset + 20));
      const value = rawValue.trim();
      if (isProfile) {
        pst.vars[key] = value;
