  // B. {{getvar::key}}  / {{getvar::profile::key}} / {{getvar::session::key::filter}}
  // ==========================================================
  content = content.replace(
    /\{\{getvar::(?:profile::|session::)?([^:}]+)(?:::([^}]*))?\}\}/g,
    (match, key, filter, offset, src) => {
      const isProfile = /\{\{getvar::profile::/.test(src.slice(Math.max(0, offset - 25), offset + 25));
      let val = isProfile ? pst.vars[key] : (mem.vars[key] !== undefined ? mem.vars[key] : pst.vars[key]);
