    /<\|cache_block\|>([\s\S]*?)<\/\|cache_block\|>/g,
    (match, block) => {
      const h = hashStr(block.trim());
      if (mem.cachedHashes.has(h) || pst.hashes[h]) {
        // 更新持久化命中时间
        pst.hashes[h] = now();
        savePersistent(persistent);
        return `[cache_hit#${h}]`;
      }
      mem.cachedHashes.add(h);
      pst.hashes[h] = now();
      savePersistent(persistent);
      return block.trim();
    }
  );

